"use strict";function encodeCred(){var e=document.getElementById("in_username").value,t=document.getElementById("in_password").value;document.getElementById("cred_output").value=btoa(e+":"+t)}function decodeCred(){var e=document.getElementById("cred_input").value;if(e){var t=atob(e).split(":");document.getElementById("out_username").value=t[0]||"",document.getElementById("out_password").value=t[1]||""}}function convertText(){var e=document.getElementById("base64str").value;document.getElementById("outputBase64").textContent=atob(e)}function convertTextR(){var e=document.getElementById("base64strR").value;document.getElementById("outputBase64R").textContent=btoa(e)}function convertImage(){var e=document.getElementById("imageUpload").files[0],t=new FileReader;t.onloadend=function(){var e=t.result;document.getElementById("outputBase64URL").textContent=e.toString()},t.readAsDataURL(e)}function convertToImage(){var e=document.getElementById("inputBase64URL").value;e&&(document.getElementById("outputImage").src=e)}function downloadImage(){var e=document.getElementById("inputBase64URL").value;if(e){var t=document.createElement("a");t.href=e,t.download=String(Date.now()),t.click()}}function copyContentOf(e){var t=document.getElementById(e).value;t&&navigator.clipboard.writeText(t).then(function(){},function(){alert("Copy failed.")})}